local MoneyCache = {}

local function getWallet()
    if Game:getPlayer() then
        return Game:getPlayer():getWallet()
    end
    return nil
end

PlayerWallet = {}

function PlayerWallet:destroy()
    MoneyCache = {}
end

---设置自定义货币当前数量，可用于PayHelper检测货币是否足够
function PlayerWallet:setMoneyCount(coinId, count)
    MoneyCache[coinId] = count
end

---通过货币类型获取货币数量，查询不到返回9999999999
function PlayerWallet.getMoneyByCoinId(coinId)
    if coinId > 3 then
        return MoneyCache[coinId] or 9999999999
    end
    local wallet = getWallet()
    if wallet then
        return NumberUtil.int64ToNumber(wallet:getMoneyByCoinId(coinId))
    end
    return 0
end

